        @mcp.tool()
        async def words_find_and_replace(
            input_filename: str,
            find_text: str,
            replace_text: str,
            output_filename: str,
        ) -> dict:
            """Find and replace text in a Word document.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the source document, e.g. ``'report.docx'``.
                find_text: Text to search for within the document.
                replace_text: Text that will replace each occurrence of ``find_text``.
                output_filename: Bare filename for the updated document, e.g. ``'report_updated.docx'``.
        
            Returns:
                dict: Contains at minimum ``status``, ``message`` and ``output_filename``. On success ``status`` is ``"success"``.
        
            Raises:
                FileNotFoundError: If the input file does not exist.
                Exception: Any unexpected error raised by Aspose.Words.
        
            Example:
                >>> await words_find_and_replace(
                ...     input_filename="report.docx",
                ...     find_text="Old Company",
                ...     replace_text="New Company",
                ...     output_filename="report_updated.docx",
                ... )
            """
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # Sanitize and resolve the input document
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # Sanitize and resolve the output document
            output_filename = Path(output_filename.strip().replace("\x00", "")).name
            resolved_output = get_safe_path(output_filename)
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            try:
                import aspose.words as aw
        
                doc = aw.Document(str(resolved_input))
                doc.range.replace(find_text, replace_text, aw.replacing.FindReplaceOptions())
                doc.save(str(resolved_output))
        
                logger.info(
                    "Replaced text in %s and saved result to %s", input_filename, output_filename
                )
                return {
                    "status": "success",
                    "message": f"Replacements applied and saved to {output_filename}",
                    "output_filename": output_filename,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Error during find and replace")
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": output_filename,
                }

        @mcp.tool()
        async def words_mail_merge(
            input_filename: str,
            field_names: list[str],
            values: list[str],
            output_filename: str | None = None,
        ) -> dict:
            """
            Perform a mail‑merge on a Word template using Aspose.Words.
        
            IMPORTANT: All *_filename parameters accept ONLY the bare filename (e.g. 'template.docx') —
            no path, no directory, no drive letter, no slash. The file MUST already exist in the server's
            ASPOSE_FILES_PATH folder. Do NOT ask the user to upload a file — files are pre‑placed in that
            folder. Output files are written to the same folder; returned output_filename is the bare name
            only.
        
            Args:
                input_filename: Bare filename of the mail‑merge template document (must exist in
                    ASPOSE_FILES_PATH).
                field_names: List of merge field names present in the template.
                values: List of values corresponding to each field name; must be the same length as
                    `field_names`.
                output_filename: Bare filename for the merged output document (e.g., 'result.docx').
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file (present only on success)
                }
        
            Raises:
                FileNotFoundError: If the input template file does not exist.
                ValueError: If `field_names` and `values` lengths differ.
                Exception: Any unexpected error raised by Aspose.Words.
        
            Example:
                >>> await words_mail_merge(
                ...     input_filename="template.docx",
                ...     field_names=["FirstName", "LastName"],
                ...     values=["John", "Doe"],
                ...     output_filename="merged.docx",
                ... )
                {
                    "status": "success",
                    "message": "Mail merge completed.",
                    "output_filename": "merged.docx"
                }
            """
            # Imports required for path handling and validation – must precede Aspose import
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # Sanitize filenames
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace('\x00', '')).name
            else:
                output_filename = Path(input_filename).stem + "_merged.docx"

            # Resolve input path safely and verify existence BEFORE importing Aspose
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")

            # Resolve output path safely
            resolved_output = get_safe_path(output_filename)
            # Ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # Validate field/value arrays
            if len(field_names) != len(values):
                raise ValueError(
                    f"field_names ({len(field_names)}) and values ({len(values)}) must have the same length."
                )
        
            # Import Aspose after validation
            import aspose.words as aw
        
            try:
                logger.debug(
                    "Starting mail merge: template=%s, output=%s, fields=%s",
                    input_filename,
                    output_filename,
                    field_names,
                )
                doc = aw.Document(str(resolved_input))
                doc.mail_merge.execute(field_names, values)
                doc.save(str(resolved_output))
                logger.info("Mail merge completed successfully: %s", output_filename)
                return {
                    "status": "success",
                    "message": "Mail merge completed.",
                    "output_filename": output_filename,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Mail merge failed")
                return {"status": "error", "message": str(exc)}

