        @mcp.tool()
        async def words_compare_documents(
            input_filename: str,
            compare_filename: str,
            author: str,
            output_filename: str,
        ) -> dict:
            """
            Compare two Word documents and produce a document with tracked changes.
        
            IMPORTANT:
            All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            Do NOT ask the user to upload a file — files are pre-placed in the server folder by the user.
            The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the original document, e.g. "original.docx".
                compare_filename: Bare filename of the revised document to compare against, e.g. "revised.docx".
                author: Name of the reviewer whose name will appear in the tracked changes.
                output_filename: Bare filename for the resulting comparison document, e.g. "result.docx".
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str (bare name of the written file, present only on success)
                }
        
            Raises:
                FileNotFoundError: If either input or compare file does not exist in ASPOSE_FILES_PATH.
                Exception: Any unexpected error raised by Aspose.Words.
        
            Example:
                >>> await words_compare_documents(
                        input_filename="contract_v1.docx",
                        compare_filename="contract_v2.docx",
                        author="Alice",
                        output_filename="contract_comparison.docx"
                    )
                {"status":"success","message":"Documents compared successfully.","output_filename":"contract_comparison.docx"}
            """
            # ----------------------------------------------------------------------
            # Imports that are NOT Aspose (must appear before any Aspose import)
            # ----------------------------------------------------------------------
            from pathlib import Path
            import logging
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            logger = logging.getLogger(__name__)
        
            # ----------------------------------------------------------------------
            # Sanitize and resolve input filenames
            # ----------------------------------------------------------------------
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            compare_filename = Path(compare_filename.strip().replace('\x00', '')).name
            output_filename = Path(output_filename.strip().replace('\x00', '')).name
        
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            resolved_compare = get_safe_path(compare_filename)
            if not Path(resolved_compare).is_file():
                raise FileNotFoundError(f"File not found: {compare_filename}")
        
            # Resolve output path (always within ASPOSE_FILES_PATH)
            resolved_output = get_safe_path(output_filename)
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Aspose.Words processing
            # ----------------------------------------------------------------------
            try:
                import aspose.words as aw
                from datetime import datetime
        
                doc1 = aw.Document(str(resolved_input))
                doc2 = aw.Document(str(resolved_compare))
                doc1.compare(doc2, author, datetime.now())
                doc1.save(str(resolved_output))
        
                return {
                    "status": "success",
                    "message": "Documents compared successfully.",
                    "output_filename": output_filename,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Error during document comparison")
                return {
                    "status": "error",
                    "message": str(exc),
                }

