        @mcp.tool()
        async def words_add_text_watermark(
            input_filename: str,
            text: str,
            output_filename: str,
            font_size: int | None = None,
            is_diagonal: bool | None = None,
        ) -> dict:
            """
            Add a text watermark to a Word document stored on the server.
        
            IMPORTANT: All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') —
            no path, no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_FILES_PATH folder.
            Do NOT ask the user to upload a file — files are pre‑placed in that folder.
            Output files are written to the same folder; returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the source document, e.g. 'report.docx'.
                text: Watermark text to apply.
                output_filename: Bare filename for the watermarked document, e.g. 'report_watermarked.docx'.
                font_size: Optional font size for the watermark text. If omitted a default size is used.
                is_diagonal: Optional flag – if true the watermark is placed diagonally, otherwise horizontally.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file
                }
        
            Example:
                >>> await words_add_text_watermark(
                ...     input_filename="report.docx",
                ...     text="CONFIDENTIAL",
                ...     output_filename="report_watermarked.docx",
                ...     font_size=48,
                ...     is_diagonal=True,
                ... )
                {
                    "status": "success",
                    "message": "Watermark applied and saved as report_watermarked.docx",
                    "output_filename": "report_watermarked.docx"
                }
        
            Raises:
                FileNotFoundError: If the input file does not exist.
                ValueError: If an invalid font size is supplied.
                Exception: Any unexpected error from Aspose.Words.
            """
            import logging
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            logger = logging.getLogger(__name__)
        
            # ---- Validate and resolve input file ----
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ---- Validate and resolve output file ----
            output_filename = Path(output_filename.strip().replace("\x00", "")).name
            resolved_output = get_safe_path(output_filename)
            # Ensure the output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            try:
                # Lazy import of Aspose.Words
                import aspose.words as aw
                import aspose.pydrawing  # needed for Color if user wants to customize later
        
                # Load document
                doc = aw.Document(str(resolved_input))
        
                # Configure watermark options
                opts = aw.TextWatermarkOptions()
                if font_size is not None:
                    if not isinstance(font_size, int) or font_size <= 0:
                        raise ValueError("font_size must be a positive integer")
                    opts.font_size = font_size
        
                # Layout selection
                if is_diagonal:
                    opts.layout = aw.WatermarkLayout.DIAGONAL
                else:
                    opts.layout = aw.WatermarkLayout.HORIZONTAL
        
                # Apply watermark
                doc.watermark.set_text(text, opts)
        
                # Save result
                doc.save(str(resolved_output))
        
                return {
                    "status": "success",
                    "message": f"Watermark applied and saved as {output_filename}",
                    "output_filename": output_filename,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to add text watermark")
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": output_filename,
                }

