        async def words_append_document(
            base_filename: str,
            append_filename: str,
            output_filename: str,
        ) -> dict:
            """
            Append the content of one Word document to another.
        
            IMPORTANT:
            - All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            - The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            - Do NOT ask the user to upload a file — files are pre-placed in the server folder by the user.
            - The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                base_filename: Bare filename of the base document (must exist in ASPOSE_FILES_PATH).
                append_filename: Bare filename of the document to append (must exist in ASPOSE_FILES_PATH).
                output_filename: Bare filename for the combined document to be written to ASPOSE_FILES_PATH.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file
                }
        
            Raises:
                FileNotFoundError: If either input file does not exist.
                Exception: Any unexpected error from Aspose.Words.
        
            Example:
                result = await words_append_document(
                    base_filename="report.docx",
                    append_filename="appendix.docx",
                    output_filename="combined.docx",
                )
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input filenames
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize base file name
            base_filename = Path(base_filename.strip().replace("\x00", "")).name
            resolved_base = get_safe_path(base_filename)
            if not Path(resolved_base).is_file():
                raise FileNotFoundError(f"File not found: {base_filename}")
        
            # sanitize append file name
            append_filename = Path(append_filename.strip().replace("\x00", "")).name
            resolved_append = get_safe_path(append_filename)
            if not Path(resolved_append).is_file():
                raise FileNotFoundError(f"File not found: {append_filename}")
        
            # ----------------------------------------------------------------------
            # Resolve output filename (may be None, but function signature expects str)
            # ----------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # fallback to a temporary file if caller omitted the name
                resolved_output = str(temp_output_path("aspose_words_result", ".docx"))
                output_filename = Path(resolved_output).name
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Perform the append operation using Aspose.Words
            # ----------------------------------------------------------------------
            try:
                import aspose.words as aw
        
                dst = aw.Document(str(resolved_base))
                src = aw.Document(str(resolved_append))
                dst.append_document(src, aw.ImportFormatMode.KEEP_SOURCE_FORMATTING)
                dst.save(str(resolved_output))
        
                logger.info(
                    "Appended document '%s' to '%s', result saved as '%s'",
                    append_filename,
                    base_filename,
                    output_filename,
                )
                return {
                    "status": "success",
                    "message": "Documents appended successfully.",
                    "output_filename": output_filename,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to append documents: %s", exc)
                return {"status": "error", "message": str(exc)}

        @mcp.tool()
        async def words_split_by_pages(
            input_filename: str,
            output_prefix: str | None = "page_",
        ) -> dict:
            """
            Split a multi‑page document into separate one‑page files.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.docx') — no path,
              no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output files are also written to the ASPOSE_FILES_PATH folder; the returned
              output_filename is the bare name of the first generated page file.
        
            Args:
                input_filename: Bare filename of the source multi‑page document.
                output_prefix:  Prefix for generated page files (default "page_").
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the first page file (or empty on error)
                }
        
            Raises:
                FileNotFoundError: If the input file does not exist.
                Exception: Any unexpected error from Aspose.Words.
        
            Example:
                result = await words_split_by_pages("report.docx", "report_page_")
                # result["output_filename"] -> "report_page_1.docx"
            """
            # -------------------------------------------------------------------------
            # Resolve and validate input file
            # -------------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize the bare filename supplied by the caller
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
        
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ensure a non‑empty prefix
            if not output_prefix:
                output_prefix = "page_"
        
            try:
                # -----------------------------------------------------------------
                # Import Aspose after validation (lazy import as required)
                # -----------------------------------------------------------------
                import aspose.words as aw
        
                # Load the source document
                doc = aw.Document(str(resolved_input))
        
                output_files: list[str] = []
        
                # Iterate over each page and save it as a separate document
                for i in range(doc.page_count):
                    page_doc = doc.extract_pages(i, 1)
        
                    # Build a safe filename for the page
                    page_filename = f"{output_prefix}{i + 1}.docx"
                    page_filename = Path(page_filename.strip().replace("\x00", "")).name
        
                    # Resolve the absolute path where the page will be written
                    resolved_page = get_safe_path(page_filename)
        
                    # Ensure the target directory exists
                    Path(resolved_page).parent.mkdir(parents=True, exist_ok=True)
        
                    # Save the single‑page document
                    page_doc.save(str(resolved_page))
        
                    output_files.append(page_filename)
        
                page_count = len(output_files)
                logger.info(
                    "Successfully split %s into %d page files.", input_filename, page_count
                )

                return {
                    "status": "success",
                    "message": f"Document split into {page_count} pages.",
                    "output_filename": output_files[0] if output_files else "",
                    "output_files": output_files,
                    "page_count": page_count,
                }

            except Exception as exc:  # pragma: no cover
                logger.exception("Error splitting document %s: %s", input_filename, exc)
                return {"status": "error", "message": str(exc), "output_filename": ""}

