            if not Path(resolved_image).is_file():
                raise FileNotFoundError(f"File not found: {image_filename}")
        
            # output document
            output_filename = Path(output_filename.strip().replace("\x00", "")).name
            resolved_output = (
                get_safe_path(output_filename)
                if output_filename
                else str(temp_output_path("aspose_words_result", ".docx"))
            )
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ---------- Aspose.Words processing ----------
            import aspose.words as aw
        
            try:
                doc = aw.Document(str(resolved_input))
                builder = aw.DocumentBuilder(doc)
                builder.insert_image(str(resolved_image))
                doc.save(str(resolved_output))
        
                return {
                    "status": "success",
                    "message": "Image inserted successfully.",
                    "output_filename": output_filename,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Error inserting image into document")
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": output_filename,
                }
